wire en;
reg [7:0] data;
initial begin en = 0; end
always @(posedge clk) if (en) mem[addr] = data;

wire [1:0] mem_addr, w_addr;
wire mem_en, w_en;
wire [7:0] mem_data, w_data;
initial mem_addr = 0;
initial mem_en = 0;
initial mem_data = 0;
always_comb begin mem_addr = w_addr; mem_en = w_en; mem_data = w_data; end

input [1:0] w_addr;
input w_en;
wire [1:0] mem_w_addr;
wire mem_w_en;
assign mem_w_addr = w_addr;
assign mem_w_en = w_en;
